targets.expr:
sum(
  outline_ws_uplink_open_connections{job=~"$job",instance=~"$instance",group=~"$group"}
  unless on(instance, group, uplink) (outline_ws_global_active_uplink_info{job=~"$job",instance=~"$instance",group=~"$group"} == 1)
  unless on(instance, group, transport, uplink) (outline_ws_per_uplink_active_uplink_info{job=~"$job",instance=~"$instance",group=~"$group"} == 1)
)
